// Merge perf rows with their rule by campaignId, then apply decision logic.
const perfRows = $node['Read performance'].json && Array.isArray($node['Read performance'].json) ? $node['Read performance'].json : $items('Read performance').map(i => i.json);
const ruleRows = $items('Read rules').map(i => i.json);
const rulesById = Object.fromEntries(ruleRows.map(r => [String(r.campaignId), r]));

const out = [];
for (const p of perfRows) {
  const r = rulesById[String(p.campaignId)];
  if (!r) {
    out.push({ ...p, action: 'hold', reason: 'no rule defined' });
    continue;
  }
  const targetCpa = Number(r.target_cpa || 0);
  const targetRoas = Number(r.target_roas || 0);
  const pauseT = Number(r.pause_threshold || 1.5);
  const scaleT = Number(r.scale_threshold || 0.7);
  const scaleIncr = Number(r.scale_increment || 0.2);
  const cpa = Number(p.cpa || 0);
  const roas = Number(p.roas || 0);

  if (targetCpa > 0 && cpa > targetCpa * pauseT) {
    out.push({ ...p, action: 'pause', reason: `cpa ${cpa.toFixed(2)} > target ${targetCpa} * ${pauseT}` });
  } else if (targetCpa > 0 && cpa > 0 && cpa < targetCpa * scaleT && roas > targetRoas) {
    out.push({ ...p, action: 'scale_up', delta: scaleIncr, reason: `cpa ${cpa.toFixed(2)} < target ${targetCpa} * ${scaleT} and roas ${roas.toFixed(2)} > ${targetRoas}` });
  } else {
    out.push({ ...p, action: 'hold', reason: 'within targets' });
  }
}
return out.map(json => ({ json }));
